ee:variables.ee:set-variable:
%dw 2.0
output application/java
fun toObject(row: Array, headers: Array) = { 
    (headers map ((colName, index) -> (colName): row[index] default "" )) 
}
var searchIdx = (vars.headerParsed.headers map lower($)) indexOf "service_call_id"
var headerIdIndex = if (searchIdx >= 0) searchIdx else 0
---
vars.headerParsed.rows map ((hRow) -> do {
    var joinId = hRow[headerIdIndex] default ""
    var baseObj = toObject(hRow, vars.headerParsed.headers)
    var childNotes = (vars.notesData.map[joinId] default []) map (nRow) -> toObject(nRow, vars.notesData.headers)
    var childMaterials = vars.materialsJoinMap[joinId] default []
    ---
    baseObj ++ { 
        "app_notes" : childNotes, 
        "order_materials": childMaterials 
    }
})

%dw 2.0
output application/json
---
{
    sql: "SELECT service_call_id FROM service_calls_v3 WHERE search_embedding IS NOT NULL AND service_call_id IN (SELECT jsonb_array_elements_text(:serviceCallIdentifiersJson::jsonb))",
    parameters: {
        serviceCallIdentifiersJson: vars.serviceCallIdentifiersJson
    }
}

ee:message.ee:set-payload:
%dw 2.0
output application/java

fun cleanText(raw) = do {
    var cleaned = trim((raw default '') replace /\u0000/ with '')
    ---
    if (cleaned == '') null else cleaned
}

fun normalizeTimestamp(raw) = do {
    var trimmed = trim((raw default '') replace "|" with "")
    var step1 = trimmed replace /(\d{2}:\d{2}:\d{2}):(\d+)$/ with (m) -> m[1] ++ "." ++ m[2]
    var step2 = step1 replace /\.(\d{4,})$/ with (m) -> '.' ++ m[1][0 to 2]
    var step3 = step2 replace /\.(\d{1,2})$/ with (m) -> '.' ++ (m[1] ++ '000')[0 to 2]
    var testStr = trim(lower(step3) replace "am" with "" replace "pm" with "" replace "t" with " " replace "z" with "")
    ---
    if (step3 == '') null 
    else if (testStr matches /^(\d{1,4}[\-\/]\d{1,2}[\-\/]\d{1,4}|\d{1,2}:\d{2}:\d{2}).*$/) step3 
    else null
}

---
(vars.allRecords filter ((rec) -> 
    (rec.Service_Call_ID default '') != '' and 
    not (vars.embeddedServiceCallLookup[rec.Service_Call_ID] default false)
)) map ((rec) -> do {
    var scId = rec.Service_Call_ID default ''
    var serviceDescription = cleanText(rec.Service_Description)
    
    var appointmentRows = (rec.app_notes default []) map (note) -> {
        service_call_id : scId,
        appt_number : cleanText(note.ApptNumber),
        office_notes : cleanText(note.OfficeNotes),
        summary_notes : cleanText(note.SummaryNotes),
        onsite_start_time : normalizeTimestamp(note.OnsiteStartTime),
        onsite_stop_time : normalizeTimestamp(note.OnsiteStopTime),
        status : cleanText(note.Status),
        followup_reason : cleanText(note.FollowupReason)
    }
    
    var serviceItemRows = ( (rec.order_materials default []) map ((mat) -> do {
        var rawDesc = trim((mat.ITEMDESC default '') replace /\u0000/ with '')
        var matKey = lower(rawDesc)
        var matId = vars.catalogMap[matKey] default null
        var trxqty = (mat.TRXQTY default '0') as Number default 0.0
        var billing = (mat.Billing_Amount default '0') as Number default 0.0
        ---
        if (rawDesc == '' or matId == null) null 
        else {
            service_call_id : scId,
            material_id : matId,
            trxqty : trxqty,
            billing_amount : billing
        }
    }) ) filter ((r) -> r != null)
    
    var combinedNotes = do {
        var notes = ((rec.app_notes default []) map ((note) -> cleanText(note.SummaryNotes))) filter ((n) -> n != null)
        ---
        if (isEmpty(notes)) null else notes joinBy ' '
    }
    
    var serviceEmbedInput = ([trim(serviceDescription default ''), trim(combinedNotes default '')] filter (p) -> p != '') joinBy ' '
    
    var finalObj = {
        serviceCallId : scId,
        serviceDescription : serviceDescription,
        problem_desc : cleanText(rec.ProblemDesc),
        custnmbr : cleanText(rec.CUSTNMBR),
        adrscode : cleanText(rec.ADRSCODE),
        division : cleanText(rec.Divisions),
        combined_notes : combinedNotes,
        appointmentRows : appointmentRows,
        serviceItemRows : serviceItemRows,
        materialIdsToIncrement : serviceItemRows map (row) -> { material_id: row.material_id },
        serviceEmbedInputTruncated : serviceEmbedInput[0 to 7999] default serviceEmbedInput
    }
    ---
    write(finalObj, "application/json")
})

