vars.parsedRecord ++ {
	searchEmbeddingVectorLiteral: if ( vars.serviceEmbeddingResponse != null ) '[' ++ ((vars.serviceEmbeddingResponse.embedding map (v) -> v as String {
		format: '0.00000000'
	}) joinBy ',') ++ ']' 
                                        else null
}

ee:variables.ee:set-variable:
%dw 2.0
output application/java
var records = payload map (read($, 'application/json'))
---
{
	serviceCallRows: records map (r) -> {
		service_call_id: r.serviceCallId,
		service_description: r.serviceDescription,
		problem_desc: r.problem_desc,
		custnmbr: r.custnmbr,
		adrscode: r.adrscode,
		division: r.division,
		combined_notes: r.combined_notes
	},
	serviceCallIds: records map (r) -> r.serviceCallId,
	embeddingUpdateRows: (records filter (r) -> r.searchEmbeddingVectorLiteral != null) map (r) -> {
		service_call_id: r.serviceCallId,
		vec_literal: r.searchEmbeddingVectorLiteral
	},
	appointmentRows: records flatMap (r) -> (r.appointmentRows default []),
	serviceItemRows: records flatMap (r) -> (r.serviceItemRows default []),
	materialIdsToIncrement: records flatMap (r) -> (r.materialIdsToIncrement default [])
}

%dw 2.0
output application/json
---
{
    sql: "CREATE UNIQUE INDEX IF NOT EXISTS uq_hvac_materials_v3_desc ON hvac_materials_v3 (LOWER(itemdesc));"
}

%dw 2.0
output application/json
---
{
    sql: "SELECT material_id::text AS material_id, LOWER(itemdesc) AS material_key, (item_embedding IS NOT NULL) AS has_embedding FROM hvac_materials_v3 WHERE LOWER(itemdesc) IN (SELECT jsonb_array_elements_text(:materialKeysJson::jsonb))",
    parameters: {
        materialKeysJson: vars.uniqueMaterialKeysJson
    }
}

%dw 2.0
output application/java
---
do {
    var existingIndex = { (vars.existingMaterialCatalogRows map (row) -> { (row.material_key): { material_id : row.material_id, has_embedding : row.has_embedding } }) }
    var newMaterials = (vars.uniqueMaterialCatalogEntries filter (mat) -> existingIndex[mat.materialKey] == null) map (mat) -> mat ++ { material_id: uuid() }
    var existingMaterialsNeedingEmbedding = (vars.uniqueMaterialCatalogEntries filter (mat) -> (existingIndex[mat.materialKey] != null) and not (existingIndex[mat.materialKey].has_embedding)) map (mat) -> mat ++ { material_id: existingIndex[mat.materialKey].material_id }
    
    var existingKeyMap = existingIndex mapObject ((value, key) -> { (key): value.material_id })
    var newKeyMap = { (newMaterials map (mat) -> { (mat.materialKey): mat.material_id }) }
    ---
    {
        newMaterialCatalogEntries : newMaterials,
        materialsNeedingEmbedding : newMaterials ++ existingMaterialsNeedingEmbedding,
        materialCatalogMap : existingKeyMap ++ newKeyMap
    }
}

ee:message.ee:set-payload:
%dw 2.0
output application/java
---
vars.materialsNeedingEmbedding map ((mat) -> do {
	var combinedText = ([trim(mat.itemnmbr default ''), trim(mat.itemdesc default ''), trim(mat.item_category default '')] filter (p) -> p != '') joinBy ' '
	var truncated = combinedText[0 to 7999] default combinedText
	---
	write({
		material_id: mat.material_id,
		itemdesc: mat.itemdesc,
		materialEmbedInputTruncated: truncated
	}, "application/json")
})

